import React from 'react';
import { Block } from './Block';
import './index.scss';

function App() {
  const [fromCurrency, setFromCurrency] =  React.useState('RUB');
  const [conversion_rates, setRates] = React.useState({});

  React.useEffect(() => {
    fetch("https://v6.exchangerate-api.com/v6/4f9f861f549296e372c9a74d/latest/USD")
    .then((res) => res.json())
    .then((json) => {
      setRates(json.conversion_rates);
      console.log(json.conversion_rates)
    }).catch(err => {
      console.warn(err);
      alert('Не удалось получить данные');
    })
  }, []);
  return (
    <div className="App">
      <Block value={0} currency="RUB" onChangeCurrency={setFromCurrency} />
      <Block value={0} currency="USD" />
    </div>
  );
}

export default App;
